challenges.template:
uniform vec2 u_resolution;
out vec4 fragColor;

// Signed distance to a rounded rectangle
// b = half-extents, r = corner radius
float sdRoundedRect(vec2 p, vec2 b, float r) {
    vec2 q = abs(p) - b + r;
    return /* ??? */ - r;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 p = uv - vec2(0.5, 0.5);  // center at origin

    float d = sdRoundedRect(p, vec2(0.3, 0.2), 0.08);

    // d < 0 means inside the shape
    float shape = smoothstep(0.01, -0.01, d);

    fragColor = vec4(shape, shape, shape, 1.0);
}

challenges.solution:
uniform vec2 u_resolution;
out vec4 fragColor;

float sdRoundedRect(vec2 p, vec2 b, float r) {
    vec2 q = abs(p) - b + r;
    return length(max(q, 0.0)) - r;
}

void main() {
    vec2 uv = gl_FragCoord.xy / u_resolution;
    vec2 p = uv - vec2(0.5, 0.5);

    float d = sdRoundedRect(p, vec2(0.3, 0.2), 0.08);

    float shape = smoothstep(0.01, -0.01, d);

    fragColor = vec4(shape, shape, shape, 1.0);
}

